function asObject(value, fallback = {}) {
  if (!value) return fallback;

  if (typeof value === "object" && !Array.isArray(value)) {
    return value;
  }

  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === "object" ? parsed : fallback;
    } catch {
      return fallback;
    }
  }

  return fallback;
}

const input = $json;

const decision = asObject(input.decision);
const contextPacket = asObject(input.context_packet);
const event = asObject(input.event);
const lead = asObject(input.lead);
const leadState = asObject(input.lead_state);
const meta = asObject(input.meta);

if (!decision.action) {
  throw new Error("Missing decision.action");
}

if (!contextPacket || Object.keys(contextPacket).length === 0) {
  throw new Error("Missing context_packet");
}

return [
  {
    json: {
      ...input,

      event,
      lead,
      lead_state: leadState,
      decision,
      context_packet: contextPacket,

      execution_meta: {
        ...(input.execution_meta || {}),
        execution_id:
          input.execution_meta?.execution_id ||
          Date.now().toString(),
        timestamp: new Date().toISOString(),
        source: "6_action_executor"
      },

      meta: {
        ...meta,
        received_by: "6_action_executor",
        original_action: decision.action
      }
    }
  }
];

const globalAllowedActions = [
  // Flujo base
  "ask_missing_data",
  "send_quote",
  "answer_question",
  "answer_objection",
  "offer_booking",
  "offer_available_slots",
  "confirm_booking",
  "schedule_followup",
  "handoff_human",

  // Prioridad 2 — flujo comercial completo
  "cancel_booking",
  "reschedule_booking",
  "collect_address",
  "confirm_address",
  "send_pre_service_instructions",
  "notify_on_the_way",
  "request_review",
  "request_referral",
  "send_service_menu",
  "recommend_service"
];

let action = $json.decision?.action;
const contextAllowedActions = $json.context_packet?.allowed_actions;
const errors = [];
function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function isFilled(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === "string" && value.trim() === "") return false;
  return true;
}

function asksRecommendation(rawText) {
  const t = normalizeText(rawText);

  return (
    t.includes("que me recomiendas") ||
    t.includes("que recomiendas") ||
    t.includes("cual me recomiendas") ||
    t.includes("cual me conviene") ||
    t.includes("no se cual elegir") ||
    t.includes("no se que servicio") ||
    t.includes("ayudame a elegir") ||
    t.includes("recomiendame")
  );
}

const state = $json.context_packet?.state || {};
const latestUserMessage = $json.context_packet?.conversation?.latest_user_message || "";

const hasCommercialContext =
  isFilled(state.service_interest) &&
  isFilled(state.vehicle_type) &&
  isFilled(state.district);

if (
  action === "recommend_service" &&
  hasCommercialContext &&
  !asksRecommendation(latestUserMessage) &&
  Array.isArray(contextAllowedActions) &&
  contextAllowedActions.includes("send_quote")
) {
  action = "send_quote";

  $json.decision = {
    ...($json.decision || {}),
    action: "send_quote",
    reason: "action_executor_guard_forced_send_quote_because_service_vehicle_district_are_complete",
    message: "",
    state_update: {
      ...($json.decision?.state_update || {}),
      service_interest: state.service_interest,
      vehicle_type: state.vehicle_type,
      district: state.district,
      stage: "qualified",
      next_goal: "send_quote",
      last_bot_action: "send_quote_in_progress",
      missing_fields: []
    }
  };
}

if (!action) {
  errors.push("Missing action");
}

if (action && !globalAllowedActions.includes(action)) {
  errors.push(`Unsupported action: ${action}`);
}

if (!Array.isArray(contextAllowedActions) || contextAllowedActions.length === 0) {
  errors.push("Missing or empty context_packet.allowed_actions");
}

if (
  action &&
  Array.isArray(contextAllowedActions) &&
  contextAllowedActions.length > 0 &&
  !contextAllowedActions.includes(action)
) {
  errors.push(
    `Action not allowed in current state: ${action}. Allowed: ${contextAllowedActions.join(", ")}`
  );
}

if (errors.length > 0) {
  return [{
    error: true,
    errors,
    original: $json
  }];
}

return [{
  ...$json,
  validation: {
    global_action_valid: true,
    context_action_valid: true,
    allowed_actions_checked: contextAllowedActions
  }
}];

const data = $json;
const ctx = data.execution_context || {};

const payloadObject = {
  ...data,
  db_operations: ["appointments", "messages", "lead_state"],
  booking_request: {
    lead_id: ctx.lead_id,
    channel: ctx.channel,
    service_interest: ctx.service_interest,
    vehicle_type: ctx.vehicle_type,
    district: ctx.district,
    booking_date: ctx.booking_date,
    booking_time: ctx.booking_time,
    slot_id: ctx.slot_id,
    availability_confirmed: ctx.availability_confirmed,
    duration_minutes: ctx.duration_minutes || 120,
    calendar_id: ctx.calendar_id || "primary",
    service_address: ctx.service_address || ctx.address || null,
    address_reference: ctx.address_reference || null,
    address_confirmed: ctx.address_confirmed === true
  },
  state_update: {
    ...(ctx.state_update || {}),
    last_bot_action: "confirm_booking_in_progress"
  }
};

return [{
  ...payloadObject,
  payload: JSON.stringify(payloadObject)
}];

const action =
  $json.execution_context?.action ||
  $json.decision?.action ||
  $json.action ||
  null;
const outcome =
  $json.outcome ||
  $json.execution_result?.outcome ||
  $json.meta?.outcome ||
  null;

const lastBotAction =
  $json.state_update?.last_bot_action ||
  $json.lead_state_update?.last_bot_action ||
  $json.execution_result?.last_bot_action ||
  null;

const bot =
  $json.message ||
  $json.message_to_send ||
  $json.meta?.bot ||
  null;

const messageSent = $json.message_sent === true;

const audit = {
  audit_id: $json.audit_id || null,
  flow_name: $json.flow_name || "action_executor",
  decision: $json.audit_decision || $json.decision || null,
  idempotency_key:
    $json.idempotency_key ||
    $json.execution_context?.idempotency_key ||
    null,
  inbound_message_id:
    $json.inbound_message_id ||
    $json.execution_context?.inbound_message_id ||
    null,
  outbound_message_id:
    $json.outbound_message_id ||
    null
};

const qaFailedReasons = [];

if (!bot) qaFailedReasons.push("bot_null");
if (messageSent !== true) qaFailedReasons.push("message_sent_not_true");
if (!audit.flow_name) qaFailedReasons.push("flow_name_null");
if (!audit.decision) qaFailedReasons.push("decision_null");
if (!audit.idempotency_key) qaFailedReasons.push("idempotency_key_null");
if (!audit.audit_id && $json.message_sent === true) {
  qaFailedReasons.push("audit_not_inserted");
}

if (!audit.inbound_message_id) {
  qaFailedReasons.push("inbound_message_id_null");
}

if (!audit.outbound_message_id && $json.outbound_message_saved === true) {
  qaFailedReasons.push("audit_outbound_message_id_null");
}
if ($json.outbound_message_saved !== true && bot) {
  qaFailedReasons.push("outbound_message_not_saved");
}
const isHandoff = action === "handoff_human";

const handoffResult = {
  human_handoff:
    $json.state_update?.human_handoff === true ||
    $json.lead_state_update?.human_handoff === true ||
    $json.handoff === true,

  handoff_case_id:
    $json.handoff_case_id ||
    $json.meta?.handoff?.handoff_case_id ||
    null,

  assigned_to:
    $json.assigned_to ||
    $json.meta?.handoff?.assigned_to ||
    null,

  assigned_team:
    $json.assigned_team ||
    $json.meta?.handoff?.assigned_team ||
    null,

  notification_sent:
    $json.notification_sent === true ||
    $json.meta?.handoff?.notification_sent === true
};

if (isHandoff) {
  if (handoffResult.human_handoff !== true) {
    qaFailedReasons.push("handoff_human_not_true");
  }

  if (!handoffResult.handoff_case_id) {
    qaFailedReasons.push("handoff_case_id_null");
  }

  if (!handoffResult.assigned_to) {
    qaFailedReasons.push("assigned_to_null");
  }

  if (!handoffResult.assigned_team) {
    qaFailedReasons.push("assigned_team_null");
  }

  if (handoffResult.notification_sent !== true) {
    qaFailedReasons.push("notification_sent_not_true");
  }
}
const proposedStateUpdate =
  $json.proposed_state_update ||
  $json.decision?.state_update ||
  {};
const sanitizedStateUpdate =
  $json.sanitized_state_update ||
  $json.state_update ||
  {};

function normalizeCompareValue(value) {
  if (value === undefined) return "__undefined__";
  if (value === null) return null;

  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed === "" ? null : trimmed;
  }

  if (Array.isArray(value)) {
    return JSON.stringify(value);
  }

  if (typeof value === "boolean") {
    return value;
  }

  return value;
}

function valuesMatch(expected, actual) {
  const e = normalizeCompareValue(expected);
  const a = normalizeCompareValue(actual);

  if (e === "__undefined__") return true;

  if (typeof e === "boolean") {
    return a === e || String(a).toLowerCase() === String(e);
  }

  return JSON.stringify(e) === JSON.stringify(a);
}

const persistedStateCurrent =
  $json.persisted_state_current ||
  $json.state?.current ||
  null;

const stateMismatchFields = [];



if ($json.state_updated === true && persistedStateCurrent) {
  const keysToCompare = [
    "stage",
    "intent_last",
    "service_interest",
    "vehicle_type",
    "district",

    "mentioned_vehicle_type",
    "confirmed_vehicle_type",
    "mentioned_district",
    "confirmed_district",

    "last_bot_action",
    "next_goal",
    "human_handoff",
    "booking_date",
    "booking_time",
    "slot_id",
    "availability_confirmed",
    "service_address",
    "address_reference",
    "address_confirmed",
    "cancellation_reason",
    "reschedule_reason",
    "last_appointment_event_id"
  ];

  for (const key of keysToCompare) {
    if (sanitizedStateUpdate[key] === undefined) continue;

  if (!valuesMatch(sanitizedStateUpdate[key], persistedStateCurrent[key])) {
  stateMismatchFields.push({
    field: key,
    expected: sanitizedStateUpdate[key],
    actual: persistedStateCurrent[key],
  });
}
}
}

if (stateMismatchFields.length > 0) {
  qaFailedReasons.push(
    "state_current_does_not_match_sanitized_state_update:" +
    JSON.stringify(stateMismatchFields)
  );
}
if ($json.state_updated === true && !persistedStateCurrent) {
  qaFailedReasons.push("state_current_missing_after_update");
}

return [{
  execution_result: {
    success: qaFailedReasons.length === 0,
    action,
    outcome,
    last_bot_action: lastBotAction,
    bot,
    message_sent: messageSent,
    message_saved: $json.outbound_message_saved === true,
    outbound_message_id: $json.outbound_message_id || null,
    state_updated: $json.state_updated === true,
    state: {
  proposed_update: proposedStateUpdate,
  sanitized_update: sanitizedStateUpdate,
  current: persistedStateCurrent,
  mismatch_fields: stateMismatchFields,
},

    handoff: isHandoff ? handoffResult : null,

    audit,
    qa: {
      passed: qaFailedReasons.length === 0,
      failed_reasons: qaFailedReasons
    },
    db_records_created: $json.records || $json.db_operations || [],
    notes: $json.notes || []
  }
}];

const original = $json.original || $json;

const decision =
  original.decision ||
  original.original?.decision ||
  null;

const contextPacket =
  original.context_packet ||
  original.original?.context_packet ||
  {};

const leadId =
  original.execution_context?.lead_id ||
  contextPacket.lead?.id ||
  original.lead?.id ||
  null;

const channel =
  original.execution_context?.channel ||
  contextPacket.lead?.channel ||
  original.event?.channel ||
  "whatsapp";

const action =
  original.execution_context?.action ||
  decision?.action ||
  null;

const inboundMessageId =
  original.execution_context?.inbound_message_id ||
  contextPacket.conversation?.last_message_id ||
  original.event?.message_id ||
  null;

const idempotencyKey =
  original.execution_context?.idempotency_key ||
  (
    leadId && inboundMessageId && action
      ? `${leadId}__${inboundMessageId}__${action}`
      : null
  );

return [
  {
    json: {
      ...original,

      error: true,
      errors: $json.errors || original.errors || ["validation error"],

      decision,
      context_packet: contextPacket,

      lead_id: leadId,
      channel,
      idempotency_key: idempotencyKey,

      execution_context: {
        ...(original.execution_context || {}),
        lead_id: leadId,
        channel,
        action,
        inbound_message_id: inboundMessageId,
        idempotency_key: idempotencyKey
      },

      message_sent: false,
      outbound_message_saved: false,
      state_updated: false,

      execution_result: {
        success: false,
        action,
        message_sent: false,
        state_updated: false,
        db_records_created: [],
        notes: $json.errors || original.errors || ["validation error"]
      },

      notes: [
        ...(original.notes || []),
        "action_executor_validation_error"
      ]
    }
  }
];

return [{
  execution_result: {
    success: true,
    action: $json.execution_context?.action || $json.decision?.action || null,
    message_sent: false,
    state_updated: false,
    db_records_created: [],
    notes: ["skipped due to idempotency"]
  }
}];

const originalInput = $("IN LLM_Descision").first().json;

const contextPacket =
  $json.context_packet ||
  originalInput.context_packet ||
  {};

const decision =
  $json.decision ||
  originalInput.decision ||
  null;

const executionContext = {
  ...($json.execution_context || {})
};

const leadId =
  executionContext.lead_id ||
  $json.lead_id ||
  contextPacket.lead?.id ||
  null;

const channel =
  executionContext.channel ||
  $json.channel ||
  contextPacket.lead?.channel ||
  "whatsapp";

const action =
  executionContext.action ||
  decision?.action ||
  $json.action ||
  null;

const inboundMessageId =
  executionContext.inbound_message_id ||
  contextPacket.conversation?.last_message_id ||
  contextPacket.event?.message_id ||
  originalInput.event?.message_id ||
  null;

const idempotencyKey =
  executionContext.idempotency_key ||
  $json.idempotency_key ||
  (
    leadId && inboundMessageId && action
      ? `${leadId}__${inboundMessageId}__${action}`
      : null
  );

if (!leadId) {
  throw new Error("Missing lead_id for audit");
}

if (!decision) {
  throw new Error("Missing decision for audit");
}

if (!idempotencyKey) {
  throw new Error("Missing idempotency_key for audit");
}

const botMessage =
  $json.message ||
  $json.message_to_send ||
  $json.execution_result?.bot ||
  $json.execution_result?.message ||
  null;

const messageSent = $json.message_sent === true;
const outboundMessageId =
  $json.outbound_message_id ||
  $json.message_id ||
  $json.message_db_id ||
  null;

const providerStatus =
  $json.provider_status ||
  ($json.message_sent === true ? "sent" : "failed");

const providerMessageId =
  $json.provider_message_id ||
  null;

return [{
  ...$json,

  flow_name: "action_executor",
  lead_id: leadId,
  inbound_message_id: inboundMessageId,
  outbound_message_id: outboundMessageId,
  provider_status: providerStatus,
  provider_message_id: providerMessageId,
  channel,
  stage_before: contextPacket.state?.stage || null,
  latest_user_message: contextPacket.conversation?.latest_user_message || null,
  allowed_actions: contextPacket.allowed_actions || [],
  decision,
  llm: null,
  idempotency_key: idempotencyKey,


  execution_context: {
    ...executionContext,
    lead_id: leadId,
    channel,
    action,
    inbound_message_id: inboundMessageId,
    idempotency_key: idempotencyKey
  },

  context_packet: contextPacket,

  meta: {
    execution_meta: $json.execution_meta || null,
    validation: $json.validation || null,
    action,
    state: {
  before: contextPacket.state || null,
  proposed_update:
    $json.proposed_state_update ||
    decision?.state_update ||
    null,
  sanitized_update:
    $json.sanitized_state_update ||
    $json.state_update ||
    null,
  current:
    $json.persisted_state_current ||
    $json.state?.current ||
    null,
},
    outcome:
      $json.outcome ||
      $json.execution_result?.outcome ||
      null,
    handoff:
      action === "handoff_human"
        ? {
            human_handoff: true,
            handoff_case_id: $json.handoff_case_id || null,
            assigned_to: $json.assigned_to || null,
            assigned_team: $json.assigned_team || null,
            notification_sent: $json.notification_sent === true,
            notification_channel: $json.notification_channel || null,
            notification_sent_at: $json.notification_sent_at || null
          }
        : null,

    last_bot_action:
      $json.state_update?.last_bot_action ||
      $json.lead_state_update?.last_bot_action ||
    null,

    bot: botMessage,
    message_sent: messageSent,

    provider_message_id: providerMessageId,
    provider_status: providerStatus,
    outbound_message_id: outboundMessageId,

    outbound_message_saved: $json.outbound_message_saved === true,

    state_updated: $json.state_updated === true,
    db_records_created: $json.records || $json.db_operations || [],
    execution_result: $json.execution_result || null,
    notes: $json.notes || []
  },

  created_at: new Date().toISOString()
}];

const decision = $json.decision || {};
const ctx = $json.execution_context || {};
const action = decision.action || null;

const requiredByAction = {
  ask_missing_data: ["lead_id", "channel", "message"],
  send_quote: ["lead_id", "channel", "service_interest", "vehicle_type", "district"],
  answer_question: ["lead_id", "channel", "message"],
  send_service_menu: ["lead_id", "channel"],
  recommend_service: ["lead_id", "channel"],
  answer_objection: ["lead_id", "channel", "message"],
  offer_booking: ["lead_id", "channel", "message", "service_interest"],cancel_booking: ["lead_id", "channel"],

reschedule_booking: ["lead_id", "channel"],

collect_address: ["lead_id", "channel"],

confirm_address: ["lead_id", "channel", "address"],

send_pre_service_instructions: ["lead_id", "channel"],

notify_on_the_way: ["lead_id", "channel"],

request_review: ["lead_id", "channel"],

request_referral: ["lead_id", "channel"],


  offer_available_slots: [
    "lead_id",
    "channel",
    "service_interest",
    "vehicle_type",
    "district"
  ],

 confirm_booking: [
  "lead_id",
  "channel",
  "service_interest",
  "vehicle_type",
  "district",
  "booking_date",
  "booking_time",
  "availability_confirmed"
],

  schedule_followup: ["lead_id", "followup_type", "scheduled_for"],
  handoff_human: ["lead_id", "handoff_reason"]
};

const required_fields = requiredByAction[action] || [];

return [
  {
    json: {
      ...$json,
      validation: {
        ...($json.validation || {}),
        action,
        required_fields
      }
    }
  }
];

const action = $json.validation?.action || null;
const missing_fields = $json.validation?.missing_fields || [];

let fallback_message = "Necesito un poco más de información para continuar.";

if (missing_fields.includes("district")) {
  fallback_message = "Perfecto. Para ayudarte bien, ¿en qué comuna estás?";
} else if (missing_fields.includes("vehicle_type")) {
  fallback_message = "Perfecto. ¿Qué tipo de vehículo tienes?";
} else if (missing_fields.includes("service_interest")) {
  fallback_message = "Perfecto. ¿Qué servicio te interesa?";
} else if (missing_fields.includes("booking_date")) {
  fallback_message = "Perfecto. ¿Para qué día te gustaría agendar?";
} else if (missing_fields.includes("booking_time")) {
  fallback_message = "Perfecto. ¿Qué horario te acomoda?";
}

let nextGoal = "collect_missing_data";

if (
  missing_fields.includes("vehicle_type") &&
  missing_fields.includes("district")
) {
  nextGoal = "collect_vehicle_and_district";
} else if (missing_fields.includes("service_interest")) {
  nextGoal = "collect_service_interest";
} else if (missing_fields.includes("vehicle_type")) {
  nextGoal = "collect_vehicle_type";
} else if (missing_fields.includes("district")) {
  nextGoal = "collect_district";
}


return [{
  ...$json,

  message_to_send: fallback_message,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...($json.state_update || {}),
    missing_fields,
    last_bot_action: "ask_missing_data",
    next_goal: nextGoal
  },

  execution_result: {
    success: false,
    action,
    message_sent: false,
    state_updated: true,
    db_records_created: ["messages", "lead_state"],
    notes: [
      "blocked_missing_requirements",
      ...missing_fields
    ],
    fallback_action: "ask_missing_data",
    fallback_message
  }
}];

const execution_context = $json.execution_context || {};
const validation = $json.validation || {};
const required_fields = validation.required_fields || [];

function getValue(path, obj) {
  return path.split('.').reduce((acc, key) => {
    if (acc === undefined || acc === null) return undefined;
    return acc[key];
  }, obj);
}

const missing_fields = required_fields.filter((field) => {
  const value = getValue(field, execution_context);

  if (value === undefined || value === null) return true;
  if (typeof value === "string" && value.trim() === "") return true;
  if (Array.isArray(value) && value.length === 0) return true;

  if (field === "availability_confirmed") {
  return execution_context.availability_confirmed !== true;
}
  return false;
});

return [
  {
    json: {
      ...$json,
      validation: {
        ...validation,
        missing_fields,
        requirements_ok: missing_fields.length === 0
      }
    }
  }
];

const data = $json;
const ctx = data.context_packet || {};
const state = ctx.state || {};
const conversation = ctx.conversation || {};
const lead = ctx.lead || {};
const event = data.event || {};
const ruleContext = ctx.rule_context || {};
const stateUpdate = data.decision?.state_update || {};

const action = data.decision?.action || "unknown_action";
const message = data.decision?.message || "";

const leadId =
  lead.id ||
  state.lead_id ||
  data.lead?.id ||
  null;

const phone =
  lead.phone ||
  data.lead?.phone ||
  event.phone ||
  null;

const channel =
  lead.channel ||
  data.lead?.channel ||
  event.channel ||
  "whatsapp";

const inboundMessageId =
  conversation.last_message_id ||
  event.message_id ||
  data.message_id ||
  data.context_packet?.event?.message_id ||
  data.execution_meta?.execution_id ||
  "no_message_id";

if (!leadId) {
  throw new Error("Missing lead_id in execution context");
}

if (!action) {
  throw new Error("Missing action in execution context");
}

if (!inboundMessageId || inboundMessageId === "no_message_id") {
